import { navigateToUrl } from 'single-spa';
import { normalizeNavPath } from './resolveNavTitle';

export const LINM_NAV_FORCE_PATH_EVENT = 'linm:nav:force-path';

/**
 * Shell navigation — when current URL is a sub-route of menu path (create/view/:id),
 * force navigate to the menu list path and notify MFE MemoryRouterSync.
 */
export function forceShellNavigate(targetPath: string, currentPathname: string): void {
  const target = normalizeNavPath(targetPath);
  const current = normalizeNavPath(currentPathname);

  if (current === target) return;

  navigateToUrl(target);

  if (current.startsWith(`${target}/`)) {
    window.setTimeout(() => {
      window.dispatchEvent(
        new CustomEvent(LINM_NAV_FORCE_PATH_EVENT, { detail: { path: target } }),
      );
    }, 0);
  }
}
