import { configureStore } from '@reduxjs/toolkit';
import { authReducer, uiReducer } from '@linm-soft-org/linm-web-common-components';

/**
 * Nav shell store — `ui` slice drives `GlobalToastHost` (cross-MFE toasts via `linm:toast:add`).
 * Message/notification inbox state lives in @linm/message and @linm/notification parcels.
 */
export const navStore = configureStore({
  reducer: {
    auth: authReducer,
    ui: uiReducer,
  },
  devTools: process.env.NODE_ENV !== 'production',
});

export type NavRootState = ReturnType<typeof navStore.getState>;
export type NavDispatch = typeof navStore.dispatch;
