import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import { navigateToUrl } from 'single-spa';
import { Tabs, type Tab } from '@linm-soft-org/linm-web-common-components';
import { useShellPathname } from '../hooks/useShellPathname';
import type { OpenWorkspaceTabInput, WorkspaceTab } from './shellWorkspaceTabTypes';
import { titleFromPath } from './shellWorkspaceTabTypes';
import styles from './ShellWorkspaceTabBar.module.css';

type ShellWorkspaceTabContextValue = {
  tabs: WorkspaceTab[];
  activeTabId: string | null;
  openWorkspaceTab: (input: OpenWorkspaceTabInput) => void;
  activateTab: (id: string) => void;
  closeTab: (id: string) => void;
};

const ShellWorkspaceTabContext = createContext<ShellWorkspaceTabContextValue | null>(null);

export type ShellWorkspaceTabProviderProps = {
  children: React.ReactNode;
  sidebarOffsetPx: number;
};

function reportTabId(returnPath: string): string {
  return `report-tab:${returnPath}`;
}

function readShellPath(): string {
  if (typeof window === 'undefined') return '/';
  return window.location.pathname + window.location.search;
}

function pickFallbackTab(tabs: WorkspaceTab[], closedIndex: number): WorkspaceTab | undefined {
  const reportTab = tabs.find(t => t.tabKind === 'report');
  if (reportTab) return reportTab;
  return tabs[Math.max(0, closedIndex - 1)] ?? tabs[0];
}

function resolveOpenWorkspaceTab(
  prev: WorkspaceTab[],
  input: OpenWorkspaceTabInput,
): { tabs: WorkspaceTab[]; activeId: string } {
  let nextTabs = [...prev];

  if (input.returnPath) {
    const anchorId = reportTabId(input.returnPath);
    if (!nextTabs.some(t => t.id === anchorId)) {
      nextTabs.unshift({
        id: anchorId,
        path: input.returnPath,
        title: input.returnTitle ?? titleFromPath(input.returnPath),
        tabKind: 'report',
      });
    }
  }

  const reuse = input.reuseExisting !== false;
  if (reuse) {
    const existing = nextTabs.find(t => t.path === input.path);
    if (existing) {
      return { tabs: nextTabs, activeId: existing.id };
    }
  }

  if (input.documentType) {
    const typeIdx = nextTabs.findIndex(
      t => t.tabKind === 'document' && t.documentType === input.documentType,
    );
    if (typeIdx >= 0) {
      const tab = nextTabs[typeIdx];
      nextTabs = nextTabs.map((t, i) =>
        i === typeIdx ? { ...t, path: input.path, title: input.title } : t,
      );
      return { tabs: nextTabs, activeId: tab.id };
    }
  }

  const id = `tab-${crypto.randomUUID()}`;
  nextTabs.push({
    id,
    path: input.path,
    title: input.title,
    tabKind: 'document',
    documentType: input.documentType,
  });
  return { tabs: nextTabs, activeId: id };
}

type ShellWorkspaceTabBarProps = {
  tabs: WorkspaceTab[];
  activeTabId: string;
  onActivate: (id: string) => void;
  onClose: (id: string) => void;
  sidebarOffsetPx: number;
};

const ShellWorkspaceTabBar: React.FC<ShellWorkspaceTabBarProps> = ({
  tabs,
  activeTabId,
  onActivate,
  onClose,
  sidebarOffsetPx,
}) => {
  const tabItems: Tab[] = useMemo(
    () =>
      tabs.map(t => ({
        id: t.id,
        label: t.title,
        closable: true,
      })),
    [tabs],
  );

  return (
    <div
      className={styles.host}
      style={{ left: sidebarOffsetPx }}
      data-testid="shell-workspace-tab-bar"
    >
      <Tabs
        tabs={tabItems}
        activeTab={activeTabId}
        onTabChange={onActivate}
        onTabClose={onClose}
        variant="underline"
        sticky
      />
    </div>
  );
};

export const ShellWorkspaceTabProvider: React.FC<ShellWorkspaceTabProviderProps> = ({
  children,
  sidebarOffsetPx,
}) => {
  const shellPathname = useShellPathname();
  const [tabs, setTabs] = useState<WorkspaceTab[]>([]);
  const [activeTabId, setActiveTabId] = useState<string | null>(null);
  const tabsRef = useRef(tabs);
  tabsRef.current = tabs;
  const skipPathSyncRef = useRef(false);
  const returnPathRef = useRef<string | null>(null);
  const navigatingRef = useRef(false);
  const activeTabIdRef = useRef(activeTabId);
  activeTabIdRef.current = activeTabId;

  useEffect(() => {
    const height = tabs.length > 0 ? '40px' : '0px';
    document.documentElement.style.setProperty('--workspace-tab-height', height);
    return () => {
      document.documentElement.style.setProperty('--workspace-tab-height', '0px');
    };
  }, [tabs.length]);

  useEffect(() => {
    if (!activeTabIdRef.current || skipPathSyncRef.current || navigatingRef.current) {
      skipPathSyncRef.current = false;
      return;
    }
    const path = readShellPath();
    setTabs(prev =>
      prev.map(t => (t.id === activeTabIdRef.current ? { ...t, path } : t)),
    );
  }, [shellPathname]);

  const openWorkspaceTab = useCallback((input: OpenWorkspaceTabInput) => {
    if (input.returnPath) {
      returnPathRef.current = input.returnPath;
    }

    const { tabs: nextTabs, activeId } = resolveOpenWorkspaceTab(tabsRef.current, input);
    tabsRef.current = nextTabs;
    setTabs(nextTabs);
    setActiveTabId(activeId);
    skipPathSyncRef.current = true;
    navigatingRef.current = true;
    navigateToUrl(input.path);
    window.setTimeout(() => {
      navigatingRef.current = false;
    }, 0);
  }, []);

  const activateTab = useCallback((id: string) => {
    const tab = tabsRef.current.find(t => t.id === id);
    if (!tab) return;
    setActiveTabId(id);
    skipPathSyncRef.current = true;
    navigatingRef.current = true;
    navigateToUrl(tab.path);
    window.setTimeout(() => {
      navigatingRef.current = false;
    }, 0);
  }, []);

  const closeTab = useCallback((id: string) => {
    const current = tabsRef.current;
    const idx = current.findIndex(t => t.id === id);
    if (idx < 0) return;
    const nextTabs = current.filter(t => t.id !== id);
    tabsRef.current = nextTabs;
    setTabs(nextTabs);

    if (nextTabs.length === 0) {
      setActiveTabId(null);
      const back = returnPathRef.current;
      if (back) {
        skipPathSyncRef.current = true;
        navigatingRef.current = true;
        navigateToUrl(back);
        returnPathRef.current = null;
        window.setTimeout(() => {
          navigatingRef.current = false;
        }, 0);
      }
      return;
    }

    if (activeTabIdRef.current !== id) return;
    const fallback = pickFallbackTab(nextTabs, idx);
    if (fallback) {
      setActiveTabId(fallback.id);
      skipPathSyncRef.current = true;
      navigatingRef.current = true;
      navigateToUrl(fallback.path);
      window.setTimeout(() => {
        navigatingRef.current = false;
      }, 0);
    }
  }, []);

  useEffect(() => {
    window.__LINM_SHELL_WORKSPACE_TABS__ = true;
    window.__LINM_OPEN_WORKSPACE_TAB__ = openWorkspaceTab;
    return () => {
      delete window.__LINM_SHELL_WORKSPACE_TABS__;
      delete window.__LINM_OPEN_WORKSPACE_TAB__;
    };
  }, [openWorkspaceTab]);

  const value = useMemo(
    () => ({
      tabs,
      activeTabId,
      openWorkspaceTab,
      activateTab,
      closeTab,
    }),
    [tabs, activeTabId, openWorkspaceTab, activateTab, closeTab],
  );

  return (
    <ShellWorkspaceTabContext.Provider value={value}>
      {children}
      {tabs.length > 0 && activeTabId ? (
        <ShellWorkspaceTabBar
          tabs={tabs}
          activeTabId={activeTabId}
          onActivate={activateTab}
          onClose={closeTab}
          sidebarOffsetPx={sidebarOffsetPx}
        />
      ) : null}
    </ShellWorkspaceTabContext.Provider>
  );
};

export function useShellWorkspaceTabsOptional(): ShellWorkspaceTabContextValue | null {
  return useContext(ShellWorkspaceTabContext);
}
