import { useEffect } from 'react';
import {
  resolveShellIcon,
  resolveShellLogoLabel,
  resolveShellNavMain,
  SHELL_ICON_PATH,
} from '../config/shellBranding';

const SIDEBAR_SELECTOR = 'aside[aria-label="Điều hướng chính"]';
const SIDEBAR_LOGO_IMG = `${SIDEBAR_SELECTOR} > div:first-child img`;
const MOBILE_RAIL_LOGO_IMG = 'button[aria-label="Mở menu"] img';
const STYLE_ID = 'linm-shell-sidebar-logo';

function toAbsoluteIconUrl(iconUrl: string): string {
  try {
    return new URL(iconUrl, window.location.origin).href;
  } catch {
    return iconUrl;
  }
}

function escapeCssUrl(url: string): string {
  return url.replace(/\\/g, '\\\\').replace(/'/g, "\\'");
}

/** CSS Modules hash class names — use structural selectors + content:url to beat React re-renders. */
function syncShellLogoStyles(iconUrl: string): void {
  if (iconUrl === SHELL_ICON_PATH) {
    document.getElementById(STYLE_ID)?.remove();
    return;
  }

  const escaped = escapeCssUrl(iconUrl);
  let style = document.getElementById(STYLE_ID) as HTMLStyleElement | null;
  if (!style) {
    style = document.createElement('style');
    style.id = STYLE_ID;
    document.head.appendChild(style);
  }
  style.textContent = `
    ${SIDEBAR_LOGO_IMG},
    ${MOBILE_RAIL_LOGO_IMG} {
      content: url('${escaped}') !important;
    }
  `;
}

function applyShellLogoDom(iconUrl: string, logoLabel: string): void {
  const absoluteIconUrl = toAbsoluteIconUrl(iconUrl);
  const imgs = document.querySelectorAll<HTMLImageElement>(
    `${SIDEBAR_LOGO_IMG}, ${MOBILE_RAIL_LOGO_IMG}`,
  );

  imgs.forEach((img) => {
    if (img.src !== absoluteIconUrl) {
      img.src = iconUrl;
    }
    if (img.alt !== logoLabel) {
      img.alt = logoLabel;
    }
  });

  const textEl = document.querySelector<HTMLElement>(`${SIDEBAR_SELECTOR} [class*="logoText"]`);
  if (textEl && textEl.textContent !== logoLabel) {
    textEl.textContent = logoLabel;
  }
}

/**
 * Sync in-app shell icon into Sidebar until common Sidebar accepts logoIconUrl.
 */
export function useShellSidebarLogo(): void {
  useEffect(() => {
    const iconUrl = resolveShellIcon();
    const logoLabel = resolveShellLogoLabel() ?? resolveShellNavMain();

    syncShellLogoStyles(iconUrl);

    const apply = () => {
      applyShellLogoDom(iconUrl, logoLabel);
    };

    apply();
    const timer = window.setTimeout(apply, 0);
    const observer = new MutationObserver(() => apply());
    observer.observe(document.body, { childList: true, subtree: true });

    return () => {
      window.clearTimeout(timer);
      observer.disconnect();
      document.getElementById(STYLE_ID)?.remove();
    };
  }, []);
}
