import React from 'react';
import {
  TopbarParcelSlot,
  TOPBAR_MESSAGE_PARCEL,
  TOPBAR_NOTIFICATION_PARCEL,
} from '@linm-soft-org/linm-web-common-components';
import { useShellTopbarFlags } from '../hooks/useShellTopbarFlags';
import { NavSwitchCompanyButton } from './NavSwitchCompanyButton';

interface NavTopbarActionsProps {
  onNavigate: (path: string) => void;
  isAdmin: boolean;
  isMobile: boolean;
  allowedCompanyCodes?: string[];
  canViewAllCompanies?: boolean;
}

/** Message + switch-company actions (Topbar rightSlot). */
export const NavTopbarRightActions: React.FC<NavTopbarActionsProps> = ({
  onNavigate,
  isAdmin,
  isMobile,
  allowedCompanyCodes,
  canViewAllCompanies,
}) => {
  const { enableMessage } = useShellTopbarFlags();

  return (
    <>
      {(isAdmin || canViewAllCompanies || (allowedCompanyCodes?.length ?? 0) > 1) && (
        <NavSwitchCompanyButton isMobile={isMobile} />
      )}
      {enableMessage && (
        <TopbarParcelSlot link={TOPBAR_MESSAGE_PARCEL} customProps={{ onNavigate }} />
      )}
    </>
  );
};

/** Notification bell (Topbar notificationSlot). Hidden when VITE_ENABLE_NOTIFICATION !== true. */
export const NavTopbarNotificationSlot: React.FC<Pick<NavTopbarActionsProps, 'onNavigate'>> = ({
  onNavigate,
}) => {
  const { enableNotification } = useShellTopbarFlags();

  if (!enableNotification) return null;

  return <TopbarParcelSlot link={TOPBAR_NOTIFICATION_PARCEL} customProps={{ onNavigate }} />;
};
