import type { NavMenuItemDto } from '../hooks/useUserPermissions';

export function normalizeNavPath(path: string): string {
  const trimmed = (path || '').trim();
  if (!trimmed || trimmed === '#') return '/';
  let normalized = trimmed.startsWith('/') ? trimmed : `/${trimmed}`;
  if (normalized.length > 1 && normalized.endsWith('/')) {
    normalized = normalized.slice(0, -1);
  }
  return normalized;
}

/**
 * Longest-prefix match against nav leaf paths — SSOT for shell topbar list-page titles.
 * Sub-routes (/new, /:id) inherit the parent menu label unless MFE overrides via linm:nav:set-title.
 */
export function resolveNavTitle(pathname: string, navItems: NavMenuItemDto[]): string {
  const path = normalizeNavPath(pathname);
  if (!navItems.length) return '';

  let best: { path: string; label: string } | null = null;

  for (const item of navItems) {
    if (item.isGroup || !item.path || item.path === '#') continue;
    const itemPath = normalizeNavPath(item.path);
    if (path === itemPath || path.startsWith(`${itemPath}/`)) {
      if (!best || itemPath.length > best.path.length) {
        best = { path: itemPath, label: item.label };
      }
    }
  }

  return best?.label ?? '';
}
